/// Test whether bit (`onset_id`, `nucleus_id`, `coda_id`, `tone_id`) is set.
/// Out-of-range ids return `false` (fail-open, never panics or indexes OOB).
pub fn is_set(onset_id: usize, nucleus_id: usize, coda_id: usize, tone_id: usize) -> bool {
    if onset_id >= NUM_ONSETS || nucleus_id >= NUM_NUCLEI || coda_id >= NUM_CODAS || tone_id >= NUM_TONES {
        return false;
    }
    let idx = bit_index(onset_id, nucleus_id, coda_id, tone_id);
    (BITS[idx / 64] >> (idx % 64)) & 1 != 0
}
